import { forwardRef } from "react";
import { Checkbox, type CheckboxProps, type CheckboxLabel } from "../Checkbox";
import { ToggleTile } from "../ToggleTile";
import type { CheckboxTileSize } from "./CheckboxTile.config";
import { DEFAULT_CHECKBOX_TILE_SIZE } from "./CheckboxTile.config";
import { useCheckboxGroupContext } from "../CheckboxGroup";

export type CheckboxTileLabel = Omit<CheckboxLabel, "asChild">;

interface CheckboxTileCustomProps {
  /**
   * The size of the tile, which controls the padding.
   * @default 'lg'
   */
  size?: CheckboxTileSize;

  /**
   * The visible label configuration for the tile (asChild is controlled internally).
   */
  label: CheckboxTileLabel;

  /**
   * Additional CSS class name(s) to apply to the tile container.
   */
  className?: string;
}

export interface CheckboxTileProps
  extends
    Omit<CheckboxProps, keyof CheckboxTileCustomProps>,
    CheckboxTileCustomProps {}

/**
 * A tile-styled checkbox component that allows clicking anywhere on the tile to toggle.
 * The entire tile is wrapped in a label element for full click area coverage.
 * The input's accessible name comes from aria-labelledby (pointing to the visible label text),
 * not from the wrapping label element (which would include the hint text).
 *
 * Must be used inside a CheckboxGroup, which manages the selection state.
 */
export const CheckboxTile = forwardRef<HTMLLabelElement, CheckboxTileProps>(
  (
    {
      size = DEFAULT_CHECKBOX_TILE_SIZE,
      className,
      disabled = false,
      ...checkboxProps
    },
    ref
  ) => {
    // Get checkbox group state from context (provided by CheckboxGroup)
    const groupState = useCheckboxGroupContext();

    // Derive checked, error, and disabled state from the CheckboxGroup context
    const isChecked = groupState.isSelected(checkboxProps.value);
    const hasError = groupState.isInvalid;
    // Combine item-level disabled with group-level disabled
    const isDisabled = disabled || groupState.isDisabled;

    return (
      <ToggleTile
        ref={ref}
        size={size}
        checked={isChecked}
        disabled={isDisabled}
        invalid={hasError}
        className={className}
      >
        <Checkbox {...checkboxProps} disabled={disabled} hideFocusRing />
      </ToggleTile>
    );
  }
);

CheckboxTile.displayName = "CheckboxTile";
